const text = $input.first().json.body?.text || '';
const apiKey = process.env.LLM_API_KEY || '';
const apiUrl = process.env.LLM_API_URL || 'https://api.anthropic.com/v1/messages';
const model = process.env.LLM_MODEL || 'claude-sonnet-4-20250514';

const systemPrompt = `You are a system reverse engineering expert. Analyze the following system documentation and extract:
1. All system modules, pages, fields, and actions as entities
2. All business flows and data flows between them as edges

RULES:
- Only extract entities and relationships that are EXPLICITLY described in the text
- Return valid JSON only

OUTPUT FORMAT:
{
  "entities": [
    { "name": "...", "type": "module", "parentName": null },
    { "name": "...", "type": "page", "parentName": "module name" },
    { "name": "...", "type": "field", "parentName": "page name", "fieldType": "string" },
    { "name": "...", "type": "action", "parentName": "page name", "actionType": "operation" }
  ],
  "edges": [
    { "sourceName": "...", "targetName": "...", "sourceType": "page", "targetType": "page", "flowType": "BUSINESS_FLOW", "status": "extracted", "label": "...", "sourceQuote": "..." }
  ]
}`;

const isOpenAI = apiUrl.includes('openai');

let requestBody;
let headers;

if (isOpenAI) {
  headers = {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + apiKey
  };
  requestBody = {
    model,
    max_tokens: 8192,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: text }
    ]
  };
} else {
  headers = {
    'Content-Type': 'application/json',
    'x-api-key': apiKey,
    'anthropic-version': '2023-06-01'
  };
  requestBody = {
    model,
    max_tokens: 8192,
    system: systemPrompt,
    messages: [{ role: 'user', content: text }]
  };
}

// Make the API call
const response = await fetch(apiUrl, {
  method: 'POST',
  headers,
  body: JSON.stringify(requestBody)
});

if (!response.ok) {
  const err = await response.text();
  throw new Error('API error: ' + response.status + ' ' + err);
}

const data = await response.json();

// Parse the response
let jsonStr = '';
if (data.content?.[0]?.text) {
  jsonStr = data.content[0].text;
} else if (data.choices?.[0]?.message?.content) {
  jsonStr = data.choices[0].message.content;
}

const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  return [{ json: { entities: [], edges: [] } }];
}

return [{ json: JSON.parse(jsonMatch[0]) }];
